// app/ambulance/page.tsx
"use client";

import { useState } from "react";
import { useJsApiLoader } from "@react-google-maps/api";
import { useLocation } from "../../hooks/useLocation";
import { useEmergency } from "../../hooks/useEmergency";
import { useAmbulanceSimulation } from "../../hooks/useAmbulanceSimulation";
import { useToast } from "../../hooks/useToast";
import MapView from "../../components/MapView";
import LiveTracker from "../../components/LiveTracker";
import DashboardStats from "../../components/DashboardStats";
import ToastContainer from "../../components/ToastContainer";

const FALLBACK_GPS = { lat: 18.9894, lng: 73.1175 }; // Panvel Station
const DEFAULT_HOSPITAL = { lat: 19.0144, lng: 73.0980 }; // MGM Hospital Panvel

const LIBRARIES: ("geometry" | "places")[] = ["geometry", "places"];

export default function AmbulancePage() {
  const { isLoaded } = useJsApiLoader({
    id: "google-map-script",
    googleMapsApiKey: process.env.NEXT_PUBLIC_GOOGLE_MAPS_API_KEY || "",
    libraries: LIBRARIES,
  });

  const { location: gpsLoc, error: gpsError } = useLocation();
  const { isActive, triggerEmergency, cancelEmergency, loading } = useEmergency();
  const { toasts, showToast, dismissToast } = useToast();

  const [destination] = useState(DEFAULT_HOSPITAL);
  const [routePoints, setRoutePoints] = useState<{ lat: number; lng: number }[]>([]);
  const [isEmergencyActive, setIsEmergencyActive] = useState(false);

  const realGpsLocation = gpsLoc || FALLBACK_GPS;

  // Use Maps DirectionsService directly for the route if backend doesn't provide it
  const generateRoute = async (origin: { lat: number; lng: number }, dest: { lat: number; lng: number }) => {
    return new Promise<{ lat: number; lng: number }[]>((resolve, reject) => {
      if (!window.google || !window.google.maps) return reject("Google Maps not loaded");

      const svc = new window.google.maps.DirectionsService();
      svc.route(
        {
          origin,
          destination: dest,
          travelMode: window.google.maps.TravelMode.DRIVING,
        },
        (result, status) => {
          if (status === "OK" && result) {
            const path: { lat: number; lng: number }[] = [];
            result.routes[0].legs[0].steps.forEach((step) => {
              if (step.polyline && step.polyline.points) {
                window.google.maps.geometry.encoding
                  .decodePath(step.polyline.points)
                  .forEach((p) => {
                    path.push({ lat: p.lat(), lng: p.lng() });
                  });
              }
            });
            resolve(path);
          } else {
            console.error("Directions request failed due to " + status);
            reject(status);
          }
        }
      );
    });
  };

  const sim = useAmbulanceSimulation({
    routePoints,
    realGpsLocation,
    isActive: isEmergencyActive,
    onToast: showToast,
    onRecalculate: async (lat, lng) => {
      showToast("Recalculating route from new position...", "warning");
      try {
        const newPath = await generateRoute({ lat, lng }, destination);
        setRoutePoints(newPath);
      } catch (e) {
        showToast("Failed to recalculate route", "warning");
      }
    },
  });

  const handleActivate = async () => {
    try {
      showToast("Activating Green Corridor System...", "info");

      // Try hitting the backend first
      let pathFromBackend = null;
      try {
        const res = await triggerEmergency({ origin: realGpsLocation, destination });
        if (res && res.route && res.route.path && res.route.path.length > 0) {
          pathFromBackend = res.route.path;
        }
      } catch (err) {
        console.warn("Backend emergency call failed, falling back to local simulation", err);
      }

      // If backend didn't provide a route, generate one client-side
      let finalPath = pathFromBackend;
      if (!finalPath) {
        showToast("Generating optimal dispatch route...", "info");
        finalPath = await generateRoute(realGpsLocation, destination);
      }

      setRoutePoints(finalPath);
      setIsEmergencyActive(true);
      showToast("Emergency Activated! System Live.", "success");
    } catch (err) {
      showToast(`Failed to generate route: ${err}`, "warning");
    }
  };

  const handleCancel = async () => {
    showToast("Terminating Green Corridor...", "warning");
    await cancelEmergency();
    setIsEmergencyActive(false);
    setRoutePoints([]);
    sim.resetSimulation();
  };

  // Setup Dashboard Stats
  const activeEmergencies = isEmergencyActive ? 1 : 0;
  const greenSignalsActivated = sim.greenSignalCount;

  return (
    <div className="min-h-screen bg-[#050B14] text-white flex flex-col font-sans overflow-hidden">
      <ToastContainer toasts={toasts} onDismiss={dismissToast} />

      {/* Top Header & Actions */}
      <header className="h-16 border-b border-gray-800 bg-[#0a0e1a]/90 flex items-center justify-between px-6 z-50 shadow-md">
        <div className="flex flex-col">
          <h1 className="text-xl font-bold tracking-widest text-white uppercase flex items-center gap-2">
            <span className="text-red-500">🚑</span> GoldenHour
            <span className="text-gray-500 font-light ml-2 border-l border-gray-700 pl-3">
              DISPATCH
            </span>
          </h1>
          {gpsError && (
            <span className="text-[10px] text-red-500 font-mono">GPS Error: {gpsError}</span>
          )}
        </div>

        <div>
          {!isEmergencyActive ? (
            <button
              onClick={handleActivate}
              disabled={loading || !isLoaded}
              className="px-6 py-2 bg-red-600 hover:bg-red-500 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold tracking-widest text-sm uppercase rounded shadow-[0_0_15px_rgba(220,38,38,0.5)] transition-all flex items-center gap-2"
            >
              {loading || !isLoaded ? (
                <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
              ) : (
                "⚡ Activate"
              )}
            </button>
          ) : (
            <button
              onClick={handleCancel}
              disabled={loading}
              className="px-6 py-2 bg-gray-800 hover:bg-gray-700 disabled:opacity-50 disabled:cursor-not-allowed text-gray-300 border border-gray-700 font-bold tracking-widest text-sm uppercase rounded transition-all"
            >
              ⏹ Terminate
            </button>
          )}
        </div>
      </header>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col p-4 gap-4 overflow-hidden h-[calc(100vh-64px)]">
        {/* Top: Stats Bar */}
        <div className="shrink-0">
          <DashboardStats
            activeEmergencies={activeEmergencies}
            availableAmbulances={42}
            resolvedToday={12}
            greenSignalsActivated={greenSignalsActivated}
          />
        </div>

        {/* Middle/Bottom: Split View */}
        <div className="flex-1 flex max-lg:flex-col gap-4 min-h-0">
          {/* Main Map Area */}
          <div className="flex-[2] lg:flex-[3] rounded-xl overflow-hidden shadow-2xl bg-[#0a0e1a]">
            {isLoaded ? (
              <MapView
                ambulancePosition={sim.ambulancePosition || realGpsLocation}
                destination={destination}
                routePoints={routePoints}
                trafficSignals={sim.trafficSignals}
                isEmergencyActive={isEmergencyActive}
                bearing={sim.bearing}
              />
            ) : (
              <div className="w-full h-full flex flex-col items-center justify-center border border-gray-800 rounded-xl">
                <div className="w-10 h-10 border-4 border-[#2979FF]/30 border-t-[#2979FF] rounded-full animate-spin" />
                <p className="mt-4 font-mono text-gray-500 text-sm tracking-widest uppercase">
                  Loading Google Maps...
                </p>
              </div>
            )}
          </div>

          {/* Right Panel: Live Tracker */}
          <div className="lg:w-[360px] xl:w-[420px] shrink-0 h-full">
            <LiveTracker
              isEmergencyActive={isEmergencyActive}
              remainingDistanceM={sim.remainingDistanceM}
              etaMinutes={sim.etaMinutes}
              nextSignalDistanceM={sim.nextSignalDistanceM}
              greenSignalCount={sim.greenSignalCount}
              totalSignalCount={sim.totalSignalCount}
              speedKmh={sim.speedKmh}
              onSpeedChange={sim.setSpeed}
              gpsLocation={realGpsLocation}
              isComplete={sim.isComplete}
              progressPercent={sim.progressPercent}
            />
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { Suspense, useState, useEffect } from "react";
import Link from "next/link";
import { useRouter, useSearchParams } from "next/navigation";

type Role = "ambulance" | "private" | "driver" | "admin" | "hospital";
type Mode = "login" | "register";

const ROLES = [
    { key: "ambulance" as Role, icon: "🚑", label: "Ambulance", desc: "Emergency services vehicle", color: "#E8571A", priority: "P-100" },
    { key: "hospital" as Role, icon: "🏥", label: "Hospital", desc: "Emergency receiving hospital", color: "#3B82F6", priority: "HOSP" },
];

function AuthContent() {
    const router = useRouter();
    const searchParams = useSearchParams();
    const [mode, setMode] = useState<"login" | "register" | "admin">("login");
    const [selectedRole, setSelectedRole] = useState<Role | null>(null);
    const [form, setForm] = useState({ email: "", password: "", name: "", phone: "", vehicleId: "" });
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");
    const [mounted, setMounted] = useState(false);

    useEffect(() => {
        setMounted(true);
        const urlMode = searchParams.get("mode");
        const urlRole = searchParams.get("role") as Role;

        // --- Persistence Logic ---
        const existingToken = localStorage.getItem("gh_token");
        const existingRole = localStorage.getItem("gh_role");

        // Only auto-redirect if the logged-in role matches the requested role
        if (existingToken && existingRole && existingRole === urlRole) {
            const routes: Record<string, string> = {
                ambulance: "/ambulance",
                admin: "/admin",
                hospital: "/hospital",
            };
            if (routes[existingRole]) {
                router.push(routes[existingRole]);
                return;
            }
        }
        // -------------------------

        if (urlRole && ["ambulance", "hospital", "admin"].includes(urlRole)) {
            setSelectedRole(urlRole);
            if (urlRole === "admin") {
                setMode("admin");
            } else if (urlMode === "register") {
                setMode("register");
            } else {
                setMode("login");
            }
        } else if (urlMode === "register") {
            setMode("register");
        } else if (urlMode === "admin") {
            setMode("admin");
            setSelectedRole("admin");
        }
    }, [searchParams, router]);



    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError("");
        if (mode === "register" && !selectedRole) {
            setError("Please select your role to continue.");
            return;
        }
        setLoading(true);

        try {
            const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000/api";

            if (mode === "register") {
                const roleMap: Record<Role, string> = {
                    ambulance: "driver",
                    private: "user",
                    driver: "driver",
                    admin: "admin",
                    hospital: "hospital",
                };
                const res = await fetch(`${API_BASE}/auth/register`, {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({
                        name: form.name,
                        email: form.email,
                        password: form.password,
                        role: roleMap[selectedRole!],
                        phone: form.phone || "0000000000",
                    }),
                });
                const data = await res.json();
                if (!res.ok) throw new Error(data.message || "Registration failed");
                localStorage.setItem("gh_token", data.token);
                localStorage.setItem("gh_user", JSON.stringify(data.user));
                localStorage.setItem("gh_role", selectedRole!);
            } else {
                const res = await fetch(`${API_BASE}/auth/login`, {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({
                        email: form.email,
                        password: form.password,
                    }),
                });
                const data = await res.json();
                if (!res.ok) throw new Error(data.message || "Login failed");
                localStorage.setItem("gh_token", data.token);
                localStorage.setItem("gh_user", JSON.stringify(data.user));
                const backendRole = data.user.role;
                const inferredRole = backendRole === "admin" ? "admin" : backendRole === "driver" ? "ambulance" : backendRole === "hospital" ? "hospital" : "private";
                localStorage.setItem("gh_role", inferredRole);
                if (!selectedRole) setSelectedRole(inferredRole as Role);
            }

            const finalRole = localStorage.getItem("gh_role") as Role || selectedRole || "ambulance";
            const routes: Record<string, string> = {
                ambulance: "/ambulance",
                private: "/private-emergency",
                driver: "/driver",
                admin: "/admin",
                hospital: "/hospital",
            };
            router.push(routes[finalRole] || "/");
        } catch (err) {
            setError(err instanceof Error ? err.message : "Authentication failed");
        } finally {
            setLoading(false);
        }
    };

    const getRoleStyles = () => {
        if (selectedRole === "hospital") return { accent: "#3B82F6", accentDark: "#2563EB", bg: "#F0F9FF" };
        if (selectedRole === "admin") return { accent: "#0F172A", accentDark: "#020617", bg: "#F8FAFC" };
        return { accent: "#E8571A", accentDark: "#C2410C", bg: "#FFFBF5" };
    };

    const styles = getRoleStyles();

    if (!mounted) return null;

    return (
        <>
            <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=DM+Sans:ital,opsz,wght@0,9..40,300;0,9..40,400;0,9..40,500;0,9..40,700&family=JetBrains+Mono:wght@400;600&display=swap');

        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

        :root {
          --orange:  ${styles.accent};
          --orange2: ${styles.accentDark};
          --amber:   #F59E0B;
          --cream:   ${styles.bg};
          --warm:    #FFF7ED;
          --slate:   #F1F5F9;
          --text:    #1E293B;
          --text2:   #334155;
          --muted:   #64748B;
          --border:  #E2E8F0;
          --card:    #FFFFFF;
          --danger:  #EF4444;
          --success: #10B981;
        }

        html, body { height: 100%; }

        body {
          background: var(--cream);
          color: var(--text);
          font-family: 'DM Sans', sans-serif;
          overflow-x: hidden;
        }

        /* Dot bg */
        body::before {
          content: '';
          position: fixed; inset: 0;
          background-image: radial-gradient(circle, rgba(232,87,26,0.1) 1px, transparent 1px);
          background-size: 28px 28px;
          pointer-events: none; z-index: 0;
        }

        /* Orbs */
        .orb {
          position: fixed; border-radius: 50%;
          filter: blur(80px); pointer-events: none; z-index: 0;
          animation: orbDrift 14s ease-in-out infinite alternate;
        }
        .orb-1 { width:500px;height:500px;background:rgba(232,87,26,0.08);top:-100px;left:-100px; }
        .orb-2 { width:400px;height:400px;background:rgba(245,158,11,0.07);bottom:0;right:-50px;animation-delay:-7s; }
        @keyframes orbDrift { 0%{transform:translate(0,0)} 100%{transform:translate(20px,15px)} }

        /* Layout */
        .auth-layout {
          display: flex; min-height: 100vh; position: relative; z-index: 1;
        }

        /* ── LEFT PANEL ── */
        .left-panel {
          flex: 1; display: none;
          flex-direction: column; justify-content: space-between;
          padding: 3rem 4rem; position: relative; overflow: hidden;
          background: linear-gradient(160deg, #fff 0%, var(--warm) 100%);
          border-right: 1px solid var(--border);
        }
        @media(min-width:1024px){ .left-panel { display: flex; } }

        /* Skyline */
        .skyline {
          position: absolute; bottom: 0; left: 0; right: 0;
          height: 200px; pointer-events: none;
        }

        /* Logo */
        .logo-wrap { display:flex;align-items:center;gap:0.6rem;text-decoration:none;position:relative;z-index:2; }
        .logo-icon  { position:relative;width:32px;height:32px;display:flex;align-items:center;justify-content:center; }
        .logo-ring  { position:absolute;width:32px;height:32px;border:2px solid var(--orange);border-radius:50%;animation:logoPulse 2s ease-out infinite; }
        .logo-ring:nth-child(2) { animation-delay:0.7s; }
        @keyframes logoPulse{0%{transform:scale(0.5);opacity:1}100%{transform:scale(2.5);opacity:0}}
        .logo-dot   { width:9px;height:9px;background:var(--orange);border-radius:50%;z-index:1;position:relative;box-shadow:0 0 10px rgba(232,87,26,0.5); }
        .logo-text  { font-family:'Bebas Neue',cursive;font-size:1.5rem;letter-spacing:0.08em;color:var(--text); }
        .logo-text em { color:var(--orange);font-style:normal; }

        /* Left middle content */
        .left-content { position:relative;z-index:2; }

        .sys-badge {
          display:inline-flex;align-items:center;gap:0.4rem;
          background:rgba(232,87,26,0.08);border:1.5px solid rgba(232,87,26,0.2);
          border-radius:100px;padding:0.3rem 0.9rem;
          font-family:'JetBrains Mono',monospace;font-size:0.67rem;
          color:var(--orange);letter-spacing:0.08em;margin-bottom:1.5rem;font-weight:600;
        }
        .sys-dot { width:6px;height:6px;background:var(--orange);border-radius:50%;animation:blink 1.2s infinite; }
        @keyframes blink{0%,100%{opacity:1}50%{opacity:0.25}}

        .left-heading {
          font-family:'Bebas Neue',cursive;
          font-size:3.2rem;line-height:0.95;letter-spacing:0.02em;
          color:var(--text);margin-bottom:1rem;
        }
        .left-heading span { color:var(--orange); }

        .left-sub { color:var(--muted);font-size:0.93rem;line-height:1.65;max-width:340px; }

        /* Mini stat cards */
        .mini-stats { display:grid;grid-template-columns:repeat(3,1fr);gap:0.75rem;margin-top:2.5rem; }
        .mini-stat {
          background:#fff;
          border:1.5px solid var(--border);
          border-radius:12px;padding:1rem;
          box-shadow: 0 2px 8px rgba(0,0,0,0.04);
          transition: transform 0.2s, box-shadow 0.2s;
        }
        .mini-stat:hover { transform: translateY(-2px); box-shadow: 0 6px 20px rgba(232,87,26,0.1); }
        .mini-stat-num { font-family:'Bebas Neue',cursive;font-size:1.7rem;color:var(--orange);letter-spacing:0.04em; }
        .mini-stat-label { font-family:'JetBrains Mono',monospace;font-size:0.62rem;color:var(--muted);letter-spacing:0.05em;margin-top:0.2rem; }

        /* Left bottom ping */
        .left-bottom { display:flex;align-items:center;gap:0.75rem;position:relative;z-index:2; }
        .ping-wrap {
          position:relative;width:44px;height:44px;
          display:flex;align-items:center;justify-content:center;flex-shrink:0;
        }
        .ping-ring {
          position:absolute;inset:0;border-radius:50%;
          border:1.5px solid rgba(232,87,26,0.4);
          animation:pingExpand 2.5s ease-out infinite;
        }
        .ping-ring:nth-child(2){animation-delay:0.8s;}
        @keyframes pingExpand{0%{transform:scale(0.5);opacity:1}100%{transform:scale(1);opacity:0}}
        .ping-dot { width:10px;height:10px;background:var(--orange);border-radius:50%;box-shadow:0 0 8px rgba(232,87,26,0.5); }
        .ping-label-top  { font-family:'JetBrains Mono',monospace;font-size:0.68rem;color:var(--orange);letter-spacing:0.06em;font-weight:600; }
        .ping-label-bot  { font-family:'JetBrains Mono',monospace;font-size:0.62rem;color:var(--muted);margin-top:0.1rem; }

        /* ── RIGHT PANEL ── */
        .right-panel {
          flex:1;display:flex;align-items:center;justify-content:center;
          padding:3rem 2rem;position:relative;z-index:1;
          overflow-y:auto;
          background: var(--cream);
        }
        .form-box { width:100%;max-width:440px; }

        /* Mobile logo */
        .mobile-logo { display:flex;align-items:center;gap:0.5rem;text-decoration:none;margin-bottom:2rem; }
        @media(min-width:1024px){ .mobile-logo { display:none; } }

        /* Mode toggle */
        .mode-toggle {
          display:flex;padding:5px;border-radius:12px;margin-bottom:2rem;
          background:#fff;border:1.5px solid var(--border);
          box-shadow: 0 2px 8px rgba(0,0,0,0.04);
        }
        .mode-btn {
          flex:1;padding:0.7rem;border-radius:8px;font-size:0.875rem;
          font-family:'DM Sans',sans-serif;font-weight:500;
          border:none;cursor:pointer;transition:all 0.25s;
        }
        .mode-btn.active  { background:var(--orange);color:#fff;font-weight:700;box-shadow: 0 2px 10px rgba(232,87,26,0.3); }
        .mode-btn.inactive { background:transparent;color:var(--muted); }
        .mode-btn.inactive:hover { color:var(--text); }

        /* Form heading */
        .form-heading { font-family:'Bebas Neue',cursive;font-size:2.6rem;line-height:0.95;margin-bottom:0.5rem;color:var(--text); }
        .form-heading span { color:var(--orange); }
        .form-sub { color:var(--muted);font-size:0.875rem;margin-bottom:1.8rem;line-height:1.55; }

        /* Role selector */
        .role-label {
          font-family:'JetBrains Mono',monospace;font-size:0.65rem;
          color:var(--muted);text-transform:uppercase;letter-spacing:0.1em;
          display:block;margin-bottom:0.6rem;font-weight:600;
        }
        .role-grid { display:grid;grid-template-columns:1fr 1fr;gap:0.6rem;margin-bottom:1.5rem; }
        .role-btn {
          display:flex;align-items:flex-start;gap:0.6rem;padding:0.8rem;
          border-radius:10px;cursor:pointer;transition:all 0.25s;
          font-family:'DM Sans',sans-serif;text-align:left;
          position:relative;
        }
        .role-btn.unselected {
          background:#fff;border:1.5px solid var(--border);
        }
        .role-btn.unselected:hover { border-color:rgba(232,87,26,0.35); box-shadow: 0 4px 16px rgba(0,0,0,0.06); transform: translateY(-1px); }
        .role-btn-icon { font-size:1.3rem;flex-shrink:0;margin-top:0.1rem; }
        .role-btn-name { font-size:0.8rem;font-weight:700;color:var(--text);display:block; }
        .role-btn-desc { font-size:0.7rem;color:var(--muted);display:block;margin-top:0.1rem; }
        .role-btn-pri  { font-family:'JetBrains Mono',monospace;font-size:0.6rem;display:block;margin-top:0.25rem;font-weight:600; }
        .role-check {
          position:absolute;top:0.5rem;right:0.5rem;
          width:17px;height:17px;border-radius:50%;
          display:flex;align-items:center;justify-content:center;
          font-size:0.55rem;font-weight:700;color:#fff;
        }

        /* Inputs */
        .field { margin-bottom:1rem; }
        .field-label {
          font-family:'JetBrains Mono',monospace;font-size:0.64rem;
          color:var(--muted);text-transform:uppercase;letter-spacing:0.1em;
          display:block;margin-bottom:0.4rem;font-weight:600;
        }
        .field-input {
          width:100%;padding:0.85rem 1rem;border-radius:10px;
          background:#fff;
          border:1.5px solid var(--border);
          color:var(--text);font-size:0.9rem;
          font-family:'DM Sans',sans-serif;
          transition:border-color 0.2s,box-shadow 0.2s;
          outline:none;
          box-shadow: 0 1px 4px rgba(0,0,0,0.04);
        }
        .field-input::placeholder { color:rgba(100,116,139,0.5); }
        .field-input:focus {
          border-color:var(--orange);
          box-shadow:0 0 0 3px rgba(232,87,26,0.1);
        }

        /* Error */
