                                    : selectedRole === "ambulance"
                                        ? <>Fleet <span>{mode === "login" ? "Login" : "Registry"}</span></>
                                        : mode === "login"
                                            ? <>Welcome <span>Back.</span></>
                                            : <>Join the <span>Network.</span></>}
                        </h1>
                        <p className="form-sub">
                            {mode === "admin"
                                ? "Administrative command and control interface."
                                : selectedRole === "hospital"
                                    ? "Connect your facility to the emergency network."
                                    : selectedRole === "ambulance"
                                        ? "Register your vehicle for priority transit."
                                        : mode === "login"
                                            ? "Sign in to access your dashboard."
                                            : "Create your account and select your role below."}
                        </p>

                        {/* Role selector — only if not preset via URL */}
                        {mode === "register" && !searchParams.get("role") && (
                            <>
                                <span className="role-label">Select Your Role *</span>
                                <div className="role-grid">
                                    {ROLES.map((r) => {
                                        const selected = selectedRole === r.key;
                                        return (
                                            <button
                                                key={r.key}
                                                type="button"
                                                className={`role-btn ${selected ? "" : "unselected"}`}
                                                onClick={() => setSelectedRole(r.key)}
                                                style={selected ? {
                                                    background: `${r.color}10`,
                                                    border: `1.5px solid ${r.color}`,
                                                    boxShadow: `0 4px 16px ${r.color}25`,
                                                } : {}}
                                            >
                                                <span className="role-btn-icon">{r.icon}</span>
                                                <span>
                                                    <span className="role-btn-name">{r.label}</span>
                                                    <span className="role-btn-desc">{r.desc}</span>
                                                    <span className="role-btn-pri" style={{ color: r.color }}>{r.priority}</span>
                                                </span>
                                                {selected && (
                                                    <span className="role-check" style={{ background: r.color }}>✓</span>
                                                )}
                                            </button>
                                        );
                                    })}
                                </div>
                            </>
                        )}

                        {/* Form */}
                        <form onSubmit={handleSubmit}>

                            {mode === "register" && (
                                <div className="field">
                                    <label className="field-label">
                                        {selectedRole === 'hospital' ? 'Hospital Name' : 'Full Name'}
                                    </label>
                                    <input
                                        className="field-input"
                                        type="text"
                                        required
                                        placeholder={selectedRole === 'hospital' ? "City Hospital" : "John Doe"}
                                        value={form.name}
                                        onChange={(e) => setForm({ ...form, name: e.target.value })}
                                    />
                                </div>
                            )}

                            {mode === "register" && (
                                <div className="field">
                                    <label className="field-label">Phone Number</label>
                                    <input
                                        className="field-input"
                                        type="tel"
                                        required
                                        placeholder="+91 98765 43210"
                                        value={form.phone}
                                        onChange={(e) => setForm({ ...form, phone: e.target.value })}
                                    />
                                </div>
                            )}

                            <div className="field">
                                <label className="field-label">Email Address</label>
                                <input
                                    className="field-input"
                                    type="email"
                                    required
                                    placeholder="you@example.com"
                                    value={form.email}
                                    onChange={(e) => setForm({ ...form, email: e.target.value })}
                                />
                            </div>

                            <div className="field">
                                <label className="field-label">Password</label>
                                <input
                                    className="field-input"
                                    type="password"
                                    required
                                    placeholder="••••••••"
                                    value={form.password}
                                    onChange={(e) => setForm({ ...form, password: e.target.value })}
                                />
                            </div>

                            {mode === "register" && selectedRole === 'ambulance' && (
                                <div className="field">
                                    <label className="field-label">
                                        Vehicle ID <span className="opt-tag">(optional)</span>
                                    </label>
                                    <input
                                        className="field-input"
                                        type="text"
                                        placeholder="AMB-MH-001"
                                        value={form.vehicleId}
                                        onChange={(e) => setForm({ ...form, vehicleId: e.target.value })}
                                    />
                                </div>
                            )}

                            {error && (
                                <div className="error-box">
                                    ⚠ {error}
                                </div>
                            )}

                            <button type="submit" className="submit-btn" disabled={loading}>
                                {loading ? (
                                    <><div className="spinner" /> Authenticating…</>
                                ) : mode === "login" ? (
                                    "Sign In →"
                                ) : mode === "admin" ? (
                                    "Admin Access →"
                                ) : (
                                    "Create Account →"
                                )}
                            </button>
                        </form>

                        {/* Toggle */}
                        {mode !== "admin" && (
                            <div className="toggle-row">
                                {mode === "login" ? "Don't have an account? " : "Already registered? "}
                                <button
                                    className="toggle-btn"
                                    onClick={() => { setMode(mode === "login" ? "register" : "login"); setError(""); }}
                                >
                                    {mode === "login" ? "Register here" : "Sign in"}
                                </button>
                            </div>
                        )}

                        {/* Back */}
                        <Link href="/" className="back-link">← Back to Golden Hour</Link>
                    </div>
                </div>
            </div>
        </>
    );
}

export default function AuthPage() {
    return (
        <Suspense fallback={
            <div style={{ backgroundColor: '#FFFBF5', height: '100vh', display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
                <div style={{ width: '32px', height: '32px', borderRadius: '50%', borderWidth: '3px', borderStyle: 'solid', borderColor: 'rgba(232,87,26,0.2)', borderTopColor: '#E8571A', animation: 'spin 1s linear infinite' }} />
            </div>
        }>
            <AuthContent />
        </Suspense>
    );
}

